import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../services/api';
import './AdminAnalytics.css';

function AdminAnalytics() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [period, setPeriod] = useState('week'); // day, week, month

  // Данные с бэкенда
  const [dashboard, setDashboard] = useState(null);
  const [popularListings, setPopularListings] = useState([]);
  const [searchStats, setSearchStats] = useState(null);
  const [priceStats, setPriceStats] = useState(null);
  const [closedDeals, setClosedDeals] = useState(null);

  useEffect(() => {
    loadAllAnalytics();
  }, [period]);

  const loadAllAnalytics = async () => {
    setLoading(true);
    setError(null);

    try {
      // Загружаем все данные параллельно
      const [dashboardData, popularData, searchData, priceData, dealsData] = await Promise.all([
        API.get('/analytics/dashboard?days=30'),
        API.get(`/analytics/listings/popular?period=${period}&limit=10`),
        API.get('/analytics/search/queries?days=7'),
        API.get('/analytics/prices'),
        API.get(`/analytics/closed-deals?period=${period}`)
      ]);

      setDashboard(dashboardData.data);
      setPopularListings(popularData.data);
      setSearchStats(searchData.data);
      setPriceStats(priceData.data);
      setClosedDeals(dealsData.data);
    } catch (err) {
      console.error('Ошибка загрузки аналитики:', err);
      setError('Не удалось загрузить данные аналитики');
    } finally {
      setLoading(false);
    }
  };

  if (!user || user.role_id !== 1) {
    return (
      <div className="analytics-error">
        <h2>🚫 Доступ запрещен</h2>
        <p>Эта страница доступна только администраторам</p>
      </div>
    );
  }

  if (loading) return <div className="loader">📊 Загрузка аналитики...</div>;
  if (error) return <div className="error">❌ {error}</div>;

  return (
    <div className="analytics-page">
      <h1>📊 Аналитика</h1>

      {/* Период */}
      <div className="period-selector">
        <button
          className={period === 'day' ? 'active' : ''}
          onClick={() => setPeriod('day')}
        >
          День
        </button>
        <button
          className={period === 'week' ? 'active' : ''}
          onClick={() => setPeriod('week')}
        >
          Неделя
        </button>
        <button
          className={period === 'month' ? 'active' : ''}
          onClick={() => setPeriod('month')}
        >
          Месяц
        </button>
      </div>

      {/* Карточки с метриками */}
      {dashboard && (
        <div className="metrics-grid">
          <div className="metric-card">
            <h3>Всего объявлений</h3>
            <p className="metric-value">{dashboard.total_listings}</p>
          </div>
          <div className="metric-card">
            <h3>Просмотров сегодня</h3>
            <p className="metric-value">{dashboard.views_today}</p>
            <span className="metric-sub">уникальных: {dashboard.unique_views_today}</span>
          </div>
          <div className="metric-card">
            <h3>Новых сегодня</h3>
            <p className="metric-value">{dashboard.new_listings_today}</p>
          </div>
          <div className="metric-card">
            <h3>Контактов сегодня</h3>
            <p className="metric-value">{dashboard.contacts_today}</p>
          </div>
        </div>
      )}

      {/* Две колонки */}
      <div className="analytics-columns">
        {/* Левая колонка - популярные объявления */}
        <div className="analytics-card">
          <h2>🔥 Популярные объявления за {period}</h2>
          <div className="listings-list">
            {popularListings.map((item, index) => (
              <div key={item.listing_id || index} className="listing-item">
                <span className="rank">{index + 1}</span>
                {item.photo && (
                  <img src={item.photo} alt="" className="listing-thumb" />
                )}
                <div className="listing-info">
                  <h4>{item.title || 'Без названия'}</h4>
                  <p>{item.address || 'Адрес не указан'}</p>
                </div>
                <div className="listing-stats">
                  <span className="views">👁 {item.views}</span>
                  <span className="price">{item.price.toLocaleString()} ₽</span>
                </div>
              </div>
            ))}
            {popularListings.length === 0 && (
              <p className="no-data">Нет данных за выбранный период</p>
            )}
          </div>
        </div>

        {/* Правая колонка - поисковые запросы */}
        <div className="analytics-card">
          <h2>🔍 Популярные запросы</h2>
          {searchStats && (
            <>
              <div className="search-summary">
                <p>Всего поисков: <strong>{searchStats.total_searches}</strong></p>
                <p>Среднее время: <strong>{searchStats.avg_search_time.toFixed(2)}с</strong></p>
              </div>
              <div className="queries-list">
                {searchStats.popular_queries.map((item, index) => (
                  <div key={index} className="query-item">
                    <span className="rank">{index + 1}</span>
                    <span className="query">"{item.query}"</span>
                    <span className="count">{item.count} раз</span>
                  </div>
                ))}
              </div>
            </>
          )}
        </div>
      </div>

      {/* Статистика цен */}
      {priceStats && (
        <div className="analytics-card">
          <h2>💰 Статистика цен (активные объявления)</h2>
          <div className="price-stats">
            <div className="stats-grid">
              <div className="stat-item">
                <span className="stat-label">Всего активных:</span>
                <span className="stat-value">{priceStats.summary.total_listings}</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Средняя цена:</span>
                <span className="stat-value">{priceStats.summary.avg_price.toLocaleString()} ₽</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Цена за м²:</span>
                <span className="stat-value">{priceStats.summary.avg_price_per_m2.toLocaleString()} ₽</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Мин. цена:</span>
                <span className="stat-value">{priceStats.summary.min_price.toLocaleString()} ₽</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Макс. цена:</span>
                <span className="stat-value">{priceStats.summary.max_price.toLocaleString()} ₽</span>
              </div>
            </div>

            <h3>По типам недвижимости</h3>
            <table className="stats-table">
              <thead>
                <tr>
                  <th>Тип</th>
                  <th>Кол-во</th>
                  <th>Ср. цена</th>
                  <th>₽/м²</th>
                </tr>
              </thead>
              <tbody>
                {priceStats.by_property_type.map((item, idx) => (
                  <tr key={idx}>
                    <td>{item.type}</td>
                    <td>{item.listings_count}</td>
                    <td>{item.avg_price.toLocaleString()} ₽</td>
                    <td>{item.avg_price_per_m2.toLocaleString()} ₽</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Закрытые сделки */}
      {closedDeals && (
        <div className="analytics-card">
          <h2>✅ Закрытые сделки за {period}</h2>
          <div className="deals-stats">
            <div className="stats-grid">
              <div className="stat-item">
                <span className="stat-label">Продано объектов:</span>
                <span className="stat-value">{closedDeals.total_closed_deals}</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Общая выручка:</span>
                <span className="stat-value">{closedDeals.total_revenue.toLocaleString()} ₽</span>
              </div>
              <div className="stat-item">
                <span className="stat-label">Среднее время продажи:</span>
                <span className="stat-value">{closedDeals.avg_days_to_sell.toFixed(1)} дней</span>
              </div>
            </div>

            <h3>По типам недвижимости</h3>
            <table className="stats-table">
              <thead>
                <tr>
                  <th>Тип</th>
                  <th>Продано</th>
                  <th>Ср. цена</th>
                  <th>Выручка</th>
                </tr>
              </thead>
              <tbody>
                {closedDeals.by_property_type.map((item, idx) => (
                  <tr key={idx}>
                    <td>{item.type}</td>
                    <td>{item.count}</td>
                    <td>{item.avg_price.toLocaleString()} ₽</td>
                    <td>{item.total_revenue.toLocaleString()} ₽</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

export default AdminAnalytics;
